insert into questions (chapter_id, question, option_a, option_b, option_c, option_d, option_e, correct_option, explanation, difficulty) values
('b0000000-0000-4000-8000-010100000000', 'Menurut modul, etika merupakan fondasi utama dalam membentuk apa saja pada diri setiap individu, khususnya PNS?', 'Karakter, integritas, dan profesionalisme', 'Kekayaan, jabatan, dan status sosial', 'Popularitas, jaringan, dan kekuasaan', 'Gelar akademik, senioritas, dan pangkat', null, 'A', 'Modul menyatakan etika adalah fondasi utama pembentuk karakter, integritas, dan profesionalisme individu, terutama bagi PNS.', 'easy'),
('b0000000-0000-4000-8000-010100000000', 'Dalam Bab Pengantar, PNS digambarkan memegang amanah ganda sebagai apa?', 'Pengusaha dan investor negara', 'Pelayan publik dan pengelola keuangan negara', 'Penegak hukum tunggal dan hakim', 'Diplomat dan juru bicara kepresidenan', null, 'B', 'PNS memegang amanah sebagai pelayan publik sekaligus pengelola keuangan negara, sehingga etika menjadi landasan penting perilakunya.', 'easy'),
('b0000000-0000-4000-8000-010100000000', 'Selain bekerja secara efektif dan efisien, apa lagi yang dituntut dari seorang PNS menurut Bab Pengantar?', 'Bekerja sebanyak mungkin tanpa memperhatikan aturan', 'Mengutamakan keuntungan pribadi dalam bertugas', 'Menjunjung tinggi nilai moral, hukum, dan kepatutan', 'Menghindari segala bentuk pengawasan atasan', null, 'C', 'PNS dituntut menjunjung tinggi nilai-nilai moral, hukum, dan kepatutan sebagai landasan perilaku di lingkungan birokrasi, bukan hanya bekerja efektif-efisien.', 'medium'),
('b0000000-0000-4000-8000-010100000000', 'Nilai moral, hukum, dan kepatutan yang dijunjung PNS berfungsi sebagai apa di lingkungan birokrasi?', 'Landasan perilaku', 'Alat promosi jabatan otomatis', 'Standar penilaian fisik pegawai', 'Syarat kenaikan gaji semata', null, 'D', 'Modul menegaskan nilai moral, hukum, dan kepatutan menjadi landasan perilaku PNS di lingkungan birokrasi, bukan sekadar syarat administratif seperti kenaikan gaji.', 'medium'),
('b0000000-0000-4000-8000-010100000000', 'Bab Pengantar modul ini pada dasarnya mengantarkan pembahasan tentang topik utama apa?', 'Etika sebagai landasan karakter dan profesionalisme PNS', 'Teknik akuntansi pemerintahan', 'Prosedur rekrutmen calon PNS', 'Strategi investasi keuangan negara', null, 'A', 'Bab Pengantar membuka modul dengan menegaskan pentingnya etika sebagai fondasi karakter, integritas, dan profesionalisme PNS, menjadi dasar bab-bab selanjutnya.', 'easy'),
('b0000000-0000-4000-8000-010200000000', 'Siapakah tokoh yang mengemukakan 7 (tujuh) prinsip moral yang harus dimiliki dan dihayati PNS agar mampu memberikan pelayanan prima?', 'Franz Magnis-Suseno (2002)', 'Dr. A. Sonny Keraf (2002)', 'Miriam Budiardjo', 'Prof. Mahfud MD', null, 'B', 'Modul menyebutkan Dr. A. Sonny Keraf (2002) mengemukakan 7 prinsip moral PNS untuk mewujudkan pelayanan prima dalam good governance.', 'easy'),
('b0000000-0000-4000-8000-010200000000', 'Prinsip moral PNS yang menegaskan bahwa kepentingan publik adalah nilai tertinggi yang tidak dapat digantikan uang atau jabatan disebut...', 'Bertindak secara Adil', 'Profesionalisme', 'Tanggung Jawab terhadap Kepentingan Publik', 'Integritas Moral yang Tinggi', null, 'C', 'Prinsip "Tanggung Jawab terhadap Kepentingan Publik" menegaskan kepentingan publik adalah nilai tertinggi yang tidak tergantikan oleh uang atau jabatan.', 'medium'),
('b0000000-0000-4000-8000-010200000000', 'Prinsip "yang datang pertama harus pertama dilayani" merupakan perwujudan dari prinsip moral apa?', 'Jangan Menghalalkan Segala Cara untuk Mencapai Tujuan', 'Profesionalisme', 'Berpihak kepada Kebenaran dan Kejujuran', 'Bertindak secara Adil', null, 'D', 'Prinsip "Bertindak secara Adil" mencakup perlakuan tanpa diskriminasi, salah satunya diwujudkan lewat asas "yang datang pertama dilayani pertama".', 'medium'),
('b0000000-0000-4000-8000-010200000000', 'Manakah urutan yang BUKAN termasuk 7 prinsip moral PNS menurut Sonny Keraf?', 'Loyalitas terhadap atasan langsung', 'Profesionalisme', 'Integritas Moral yang Tinggi', 'Berpihak kepada Kebenaran dan Kejujuran', 'Bertindak secara Adil', 'A', '7 prinsip Sonny Keraf adalah Profesionalisme, Integritas Moral Tinggi, Tanggung Jawab pada Kepentingan Publik, Berpihak Kebenaran dan Kejujuran, Bertindak Adil, Jangan Menghalalkan Segala Cara, dan Jangan Lakukan pada Orang Lain yang Tak Ingin Dilakukan pada Anda. "Loyalitas terhadap atasan langsung" tidak termasuk di dalamnya.', 'hard'),
('b0000000-0000-4000-8000-010200000000', 'Prinsip moral ketujuh, "Jangan Lakukan pada Orang Lain Apa yang Anda Sendiri Tidak Mau Perbuatan Tersebut Dilakukan pada Anda", dalam konteks pelayanan publik berarti...', 'Selalu meminta imbalan atas jasa pelayanan', 'Jangan mempersulit atau meminta sesuatu dalam memberikan pelayanan', 'Mendahulukan kerabat dalam antrean pelayanan', 'Menunda pelayanan hingga ada insentif tambahan', null, 'B', 'Prinsip ini menuntut PNS untuk tidak mempersulit atau meminta sesuatu dalam memberikan pelayanan publik, karena PNS bertugas memberikan pelayanan prima.', 'easy'),
('b0000000-0000-4000-8000-010300000000', 'Secara etimologi, kata "etika" berasal dari bahasa Yunani kuno "ethos" yang berarti apa?', 'Perintah langsung dari penguasa kerajaan', 'Hukum tertulis yang mengikat semua warga negara', 'Adat istiadat atau kebiasaan hidup yang dianggap baik oleh suatu masyarakat', 'Sistem administrasi pemerintahan kuno', null, 'C', '"Ethos" dalam bahasa Yunani kuno berarti adat istiadat atau kebiasaan hidup yang dianggap baik oleh kalangan atau masyarakat tertentu.', 'easy'),
('b0000000-0000-4000-8000-010300000000', 'Menurut Kamus Besar Bahasa Indonesia (KBBI), berikut ini manakah yang BUKAN merupakan salah satu arti dari "etika"?', 'Kumpulan asas atau nilai moral (kode etik)', 'Sistem nilai dan norma moral yang menjadi pegangan seseorang/kelompok dalam mengatur tingkah laku', 'Ilmu tentang apa yang baik dan buruk serta hak dan kewajiban moral', 'Kumpulan peraturan tertulis yang bersanksi pidana', null, 'D', 'KBBI mendefinisikan etika sebagai: (1) sistem nilai dan norma moral pegangan tingkah laku, (2) ilmu baik-buruk dan hak-kewajiban moral, (3) kumpulan asas/nilai moral (kode etik) — bukan kumpulan peraturan pidana.', 'medium'),
('b0000000-0000-4000-8000-010300000000', 'Istilah "moral" berasal dari bahasa Latin "Mos" (jamak: "Mores"), yang memiliki kemiripan makna dengan istilah apa dalam bahasa Yunani?', '"Ethos" (etika)', '"Logos" (ilmu)', '"Demos" (rakyat)', '"Kratos" (kekuasaan)', null, 'A', 'Kata "Mos/Mores" (Latin) berarti adat kebiasaan atau cara hidup yang baik, maknanya kurang lebih sama dengan "ethos" (Yunani), sumber kata etika.', 'medium'),
('b0000000-0000-4000-8000-010300000000', 'Dalam pembahasan modul ini, istilah "etika PNS" pada akhirnya diartikan setara dengan istilah apa?', 'Peraturan disiplin pegawai', 'Kode etik PNS', 'Sumpah jabatan PNS', 'Perjanjian kinerja PNS', null, 'B', 'Modul menyatakan bahwa untuk pembahasan selanjutnya, etika PNS diartikan sebagai kode etik PNS.', 'easy'),
('b0000000-0000-4000-8000-010300000000', 'Manakah pernyataan yang paling tepat menggambarkan hubungan antara etika dan moral menurut modul ini?', 'Moral hanya berlaku bagi individu, etika hanya berlaku bagi organisasi', 'Etika dan moral adalah dua konsep yang bertentangan', 'Etika dan moral memiliki pengertian yang kurang lebih sama', 'Etika bersifat hukum positif, sedangkan moral tidak mengikat sama sekali', null, 'C', 'Modul menegaskan bahwa etika berkaitan erat dengan moral, dan keduanya memiliki pengertian yang kurang lebih sama.', 'easy'),
('b0000000-0000-4000-8000-010400000000', 'Tujuan kode etik dan kode perilaku ASN diatur dalam UU Nomor 20 Tahun 2023 tentang ASN pada pasal berapa?', 'Pasal 16', 'Pasal 3', 'Pasal 7', 'Pasal 4 ayat (1)', null, 'D', 'Pasal 4 ayat (1) UU No. 20 Tahun 2023 menyatakan kode etik dan kode perilaku bertujuan menjaga martabat dan kehormatan ASN serta kepentingan bangsa dan negara.', 'medium'),
('b0000000-0000-4000-8000-010400000000', 'Berapa jumlah nilai dasar ASN yang wajib dijunjung tinggi PNS sesuai Pasal 3 UU Nomor 20 Tahun 2023?', '7 (tujuh) nilai dasar', '5 (lima) nilai dasar', '9 (sembilan) nilai dasar', '4 (empat) nilai dasar', null, 'A', 'Pasal 3 UU No. 20 Tahun 2023 menetapkan 7 nilai dasar ASN: berorientasi pelayanan, akuntabel, kompeten, harmonis, loyal, adaptif, dan kolaboratif.', 'easy'),
('b0000000-0000-4000-8000-010400000000', 'Nilai dasar ASN yang bermakna "berdedikasi dan mengutamakan kepentingan bangsa dan negara" adalah...', 'Adaptif', 'Loyal', 'Kompeten', 'Harmonis', null, 'B', 'Loyal berarti berdedikasi dan mengutamakan kepentingan bangsa dan negara, termasuk memegang teguh Pancasila, UUD 1945, dan setia kepada NKRI.', 'easy'),
('b0000000-0000-4000-8000-010400000000', 'Peraturan Pemerintah Nomor 42 Tahun 2004 mengatur tentang apa?', 'Disiplin Pegawai Negeri Sipil', 'Manajemen Pegawai Negeri Sipil', 'Pembinaan Jiwa Korps dan Kode Etik PNS', 'Pengadaan Aparatur Sipil Negara', null, 'C', 'PP Nomor 42 Tahun 2004 mengatur tentang Pembinaan Jiwa Korps dan Kode Etik PNS, termasuk definisi kode etik pada Pasal 1 ayat (2).', 'medium'),
('b0000000-0000-4000-8000-010400000000', 'Menurut Pasal 7 PP Nomor 42 Tahun 2004, PNS wajib bersikap dan berpedoman pada etika dalam berapa ranah kehidupan?', '5 (lima) ranah', '4 (empat) ranah', '7 (tujuh) ranah', '3 (tiga) ranah', null, 'D', 'Pasal 7 PP No. 42 Tahun 2004 mengatur 5 ranah etika PNS: bernegara, berorganisasi/penyelenggaraan pemerintahan, bermasyarakat, terhadap diri sendiri, dan terhadap sesama PNS.', 'hard'),
('b0000000-0000-4000-8000-010500000000', 'Menurut modul, agar kode etik dapat benar-benar berfungsi, terdapat berapa syarat mutlak yang harus dipenuhi?', '2 (dua) syarat mutlak', '3 (tiga) syarat mutlak', '4 (empat) syarat mutlak', '5 (lima) syarat mutlak', null, 'A', 'Ada 2 syarat mutlak: (1) kode etik dibuat oleh profesi bersangkutan, dan (2) pelaksanaannya diawasi terus-menerus dengan evaluasi dan tindakan oleh komite khusus.', 'medium'),
('b0000000-0000-4000-8000-010500000000', 'Siapakah pihak yang berwenang menetapkan kode etik instansi menurut Pasal 13 dan 14 PP Nomor 42 Tahun 2004?', 'Organisasi profesi bersangkutan', 'Pejabat Pembina Kepegawaian masing-masing instansi', 'Kementerian Pendayagunaan Aparatur Negara', 'Badan Kepegawaian Negara pusat', null, 'B', 'Kode etik instansi ditetapkan oleh Pejabat Pembina Kepegawaian masing-masing instansi, sedangkan kode etik profesi ditetapkan oleh organisasi profesi masing-masing.', 'medium'),
('b0000000-0000-4000-8000-010500000000', 'Sesuai Pasal 101 PP Nomor 11 Tahun 2017, setiap Jabatan Fungsional (JF) wajib memiliki organisasi profesi paling lama berapa tahun sejak penetapan JF?', '10 (sepuluh) tahun', '1 (satu) tahun', '5 (lima) tahun', '3 (tiga) tahun', null, 'C', 'Pasal 101 PP No. 11 Tahun 2017 mewajibkan setiap JF memiliki 1 organisasi profesi paling lama 5 tahun sejak penetapan JF tersebut.', 'hard'),
('b0000000-0000-4000-8000-010500000000', 'Peraturan Pemerintah Nomor 11 Tahun 2017 tentang Manajemen PNS kemudian diubah dengan peraturan apa?', 'Peraturan Pemerintah Nomor 42 Tahun 2004', 'Peraturan Pemerintah Nomor 94 Tahun 2021', 'Undang-Undang Nomor 20 Tahun 2023', 'Peraturan Pemerintah Nomor 17 Tahun 2020', null, 'D', 'PP No. 11 Tahun 2017 diubah dengan PP No. 17 Tahun 2020, namun Pasal 101 mengenai organisasi profesi JF tidak mengalami perubahan.', 'medium'),
('b0000000-0000-4000-8000-010500000000', 'Manakah yang BUKAN termasuk tugas organisasi profesi Jabatan Fungsional berdasarkan Pasal 101 PP Nomor 11 Tahun 2017?', 'Menjatuhkan sanksi disiplin berat secara langsung tanpa proses Majelis', 'Menyusun dan menetapkan kode etik/kode perilaku profesi', 'Memberikan advokasi kepada anggota profesi', 'Memeriksa dan memberi rekomendasi atas pelanggaran kode etik/kode perilaku profesi', null, 'A', 'Tugas organisasi profesi JF meliputi menyusun kode etik, memberi advokasi, serta memeriksa dan merekomendasikan atas pelanggaran — bukan menjatuhkan sanksi disiplin berat secara langsung.', 'hard'),
('b0000000-0000-4000-8000-010600000000', 'Menurut Keraf (2002), agar implementasi etika baik dalam organisasi pemerintah terwujud, diperlukan berapa hal utama?', '4 (empat) hal', '5 (lima) hal', '7 (tujuh) hal', '3 (tiga) hal', null, 'B', 'Keraf (2002) menyebutkan 5 hal: komitmen moral-politik pimpinan, penerjemahan ke aturan formal, sosialisasi, penerapan sanksi/penghargaan konsekuen, dan teladan pimpinan.', 'medium'),
('b0000000-0000-4000-8000-010600000000', 'Siapakah tokoh yang mengemukakan 4 unsur utama yang mempengaruhi keberhasilan perwujudan etika dalam organisasi pemerintah?', 'Prof. Miftah Thoha', 'A. Sonny Keraf (2002)', 'Magnis-Suseno (2002)', 'Max Weber', null, 'C', 'Magnis-Suseno (2002) mengemukakan 4 unsur utama: etos kerja, moralitas pribadi, kepemimpinan yang bermutu, dan kondisi sistemik.', 'medium'),
('b0000000-0000-4000-8000-010600000000', 'Unsur "kesesuaian sikap/perilaku individu dengan norma yang berlaku" dalam kerangka Magnis-Suseno termasuk dalam unsur apa?', 'Kondisi Sistemik', 'Etos Kerja', 'Kepemimpinan yang Bermutu', 'Moralitas Pribadi', null, 'D', 'Moralitas Pribadi adalah kesesuaian sikap/perilaku dengan norma, mencakup kejujuran, tidak korupsi, dan ketaatan pada etika birokrasi.', 'medium'),
('b0000000-0000-4000-8000-010600000000', 'Dalam unsur "Kepemimpinan yang Bermutu" menurut Magnis-Suseno, pemimpin dituntut untuk konsisten, yang berarti...', 'Tidak pilih kasih dalam bersikap dan mengambil keputusan', 'Selalu mengganti kebijakan setiap bulan', 'Hanya mendengarkan pendapat bawahan senior', 'Membiarkan pelanggaran tanpa tindakan tegas', null, 'A', 'Konsistensi pemimpin berarti tidak pilih kasih, bersikap adil dan sama terhadap semua bawahan dalam pengambilan keputusan maupun sanksi.', 'hard'),
('b0000000-0000-4000-8000-010600000000', 'Kode etik organisasi pemerintah menurut modul ini tidak cukup hanya berisi kewajiban, larangan, dan sanksi karena juga membutuhkan apa?', 'Anggaran besar untuk pencetakan dokumen', 'Langkah nyata yang sistematis dan partisipasi aktif seluruh pihak', 'Persetujuan dari organisasi profesi luar negeri', 'Perubahan struktur organisasi setiap tahun', null, 'B', 'Modul menegaskan implementasi kode etik butuh langkah nyata yang sistematis serta partisipasi aktif seluruh pihak, bukan sekadar dokumen aturan.', 'medium'),
('b0000000-0000-4000-8000-010700000000', 'Surat Edaran Nomor 44/MK.01/2017 mengatur himbauan tentang apa bagi PNS Kementerian Keuangan?', 'Kode Etik dan Kode Perilaku PNS', 'Penerapan Sistem Kerja Fleksibel', 'Penerapan Nilai Dasar ASN dalam rangka Penyelenggaraan Tugas Pemerintahan', 'Penerapan Nilai-Nilai Pancasila dan Bela Negara', null, 'C', 'SE Nomor 44/MK.01/2017 mengatur Himbauan Penerapan Nilai Dasar ASN dalam rangka Penyelenggaraan Tugas Pemerintahan bagi PNS Kemenkeu.', 'medium'),
('b0000000-0000-4000-8000-010700000000', 'Kode Etik dan Kode Perilaku PNS di lingkungan Kementerian Keuangan diatur dalam peraturan apa?', 'UU Nomor 20 Tahun 2023', 'PP Nomor 42 Tahun 2004', 'KMK Nomor 416/KMK.01/2023', 'PMK Nomor 190/PMK.01/2018', null, 'D', 'PMK Nomor 190/PMK.01/2018 mengatur Kode Etik dan Kode Perilaku PNS di Lingkungan Kementerian Keuangan.', 'medium'),
('b0000000-0000-4000-8000-010700000000', 'Ada berapa Nilai-Nilai Kementerian Keuangan yang menjadi bagian dari landasan perilaku pegawai selain nilai dasar ASN?', '5 (lima) nilai', '7 (tujuh) nilai', '3 (tiga) nilai', '4 (empat) nilai', null, 'A', '5 Nilai Kemenkeu: Integritas, Profesionalisme, Sinergi, Pelayanan, dan Kesempurnaan, digabung dengan Nilai Dasar ASN sebagai landasan perilaku pegawai.', 'easy'),
('b0000000-0000-4000-8000-010700000000', 'Nilai Kemenkeu yang bermakna "senantiasa melakukan perbaikan di segala bidang untuk menjadi dan memberikan yang terbaik" adalah...', 'Sinergi', 'Kesempurnaan', 'Pelayanan', 'Integritas', null, 'B', 'Kesempurnaan berarti senantiasa melakukan perbaikan di segala bidang agar menjadi dan memberi yang terbaik, sebagai salah satu dari 5 Nilai Kemenkeu.', 'medium'),
('b0000000-0000-4000-8000-010700000000', 'Peringatan hari lahir Pancasila sebagaimana disebutkan dalam SE Nomor 12/MK.01/2019 jatuh setiap tanggal berapa?', '28 Oktober', '17 Agustus', '1 Juni', '10 November', null, 'C', 'SE Nomor 12/MK.01/2019 mewajibkan peringatan hari lahir Pancasila setiap tanggal 1 Juni sebagai bagian penerapan nilai Pancasila dan Bela Negara.', 'easy'),
('b0000000-0000-4000-8000-010800000000', 'Berdasarkan Pasal 16 PP Nomor 42 Tahun 2004, PNS yang melanggar kode etik dikenakan sanksi apa?', 'Penurunan pangkat otomatis tanpa pemeriksaan', 'Hanya pemecatan tanpa proses', 'Denda finansial langsung', 'Sanksi moral, dan dapat dikenakan tindakan administratif berupa hukuman disiplin', null, 'D', 'Pasal 16 PP No. 42 Tahun 2004 mengatur PNS pelanggar kode etik dikenakan sanksi moral, dan dapat pula dikenakan tindakan administratif berupa hukuman disiplin PNS (diatur PP 94/2021).', 'medium'),
('b0000000-0000-4000-8000-010800000000', 'Sanksi moral atas pelanggaran kode etik PNS dibuat secara tertulis dalam dua bentuk, yaitu...', 'Pernyataan tertutup atau pernyataan terbuka', 'Teguran lisan atau teguran tertulis', 'Surat peringatan pertama atau kedua', 'Penundaan gaji atau penundaan pangkat', null, 'A', 'Sanksi moral dibuat tertulis dalam bentuk pernyataan tertutup atau pernyataan terbuka sesuai Pasal 16 PP No. 42 Tahun 2004.', 'medium'),
('b0000000-0000-4000-8000-010800000000', 'Dugaan pelanggaran kode etik di Kemenkeu dapat diperoleh dari dua sumber utama, yaitu...', 'Laporan Media dan Investigasi Publik', 'Pengaduan dan/atau Temuan', 'Audit Tahunan dan Survei Pegawai', 'Rapat Evaluasi dan Sidak Rutin', null, 'B', 'Dugaan pelanggaran diperoleh dari Pengaduan (pegawai/masyarakat) dan/atau Temuan (Atasan Terlapor, Unit Kepatuhan Internal, dan/atau Inspektorat Jenderal).', 'medium'),
('b0000000-0000-4000-8000-010800000000', 'Keanggotaan Majelis Kode Etik di lingkungan Kemenkeu sekurang-kurangnya terdiri dari berapa anggota, di luar ketua dan sekretaris?', '5 (lima) orang anggota', '2 (dua) orang anggota', '3 (tiga) orang anggota', '1 (satu) orang anggota', null, 'C', 'Keanggotaan Majelis terdiri dari 1 ketua merangkap anggota, 1 sekretaris merangkap anggota, dan sekurang-kurangnya 3 orang anggota; jika lebih dari 5 orang jumlahnya harus ganjil.', 'hard'),
('b0000000-0000-4000-8000-010800000000', 'Dalam mekanisme pemanggilan oleh Majelis Kode Etik, pemanggilan pertama secara tertulis harus disampaikan paling singkat berapa hari kerja sebelum tanggal pemeriksaan?', '1 (satu) hari kerja', '3 (tiga) hari kerja', '14 (empat belas) hari kerja', '7 (tujuh) hari kerja', null, 'D', 'Pemanggilan pertama disampaikan tertulis paling singkat 7 hari kerja sebelum tanggal pemeriksaan; jika mangkir, ada pemanggilan kedua dalam 7 hari kerja berikutnya.', 'hard'),
('b0000000-0000-4000-8000-010900000000', 'Sistem Kerja Fleksibel (SKF) di Kementerian Keuangan ditetapkan melalui peraturan apa?', 'Keputusan Menteri Keuangan Nomor 416/KMK.01/2023', 'PMK Nomor 190/PMK.01/2018', 'Surat Edaran Nomor 44/MK.01/2017', 'Peraturan Pemerintah Nomor 42 Tahun 2004', null, 'A', 'SKF ditetapkan melalui KMK Nomor 416/KMK.01/2023 sebagai respons terhadap dinamika teknologi, tuntutan fleksibilitas, dan work-life balance.', 'medium'),
('b0000000-0000-4000-8000-010900000000', 'Sistem Kerja Fleksibel terdiri dari dua jenis fleksibilitas, yaitu...', 'Fleksibilitas gaji dan fleksibilitas tunjangan', 'Fleksibilitas tempat bekerja dan fleksibilitas waktu bekerja', 'Fleksibilitas jabatan dan fleksibilitas pangkat', 'Fleksibilitas cuti dan fleksibilitas lembur', null, 'B', 'SKF terdiri dari fleksibilitas tempat bekerja dan fleksibilitas waktu bekerja, didukung sarana perangkat keras, lunak, dan prasarana lainnya.', 'easy'),
('b0000000-0000-4000-8000-010900000000', 'Menurut modul, berapa banyak aspek kode etik penting yang harus diperhatikan selama pelaksanaan SKF?', '9 (sembilan) aspek', '4 (empat) aspek', '6 (enam) aspek', '3 (tiga) aspek', null, 'C', '6 aspek kode etik selama SKF: disiplin & kejujuran waktu kerja, tanggung jawab & integritas data, etika sosial & kesopanan digital, penggunaan sarana-prasarana etis, kepatuhan pengawasan & evaluasi, serta etika komunikasi & kolaborasi.', 'medium'),
('b0000000-0000-4000-8000-010900000000', 'Surat Edaran Menteri Keuangan Nomor SE-42/MK.01/2020 mengatur tentang apa?', 'Penerapan Nilai-Nilai Kementerian Keuangan sebagai Early Warning System', 'Sistem Kerja dalam Masa Transisi Normal Baru', 'Pelantikan dengan Media Elektronik', 'Panduan Etika dalam Acara Resmi Kedinasan yang Dilaksanakan Secara Virtual', null, 'D', 'SE-42/MK.01/2020 mengatur Panduan Etika dalam Acara Resmi Kedinasan yang Dilaksanakan Secara Virtual, didasarkan pada SE-22/MK.1/2020 dan SE BKN Nomor 10/SE/IV/2020.', 'hard'),
('b0000000-0000-4000-8000-010900000000', 'Dalam suatu rapat kedinasan virtual, seorang pegawai mematikan kamera sepanjang acara dan tidak menyalakan mikrofon meski diminta merespons pimpinan. Perilaku ini paling tidak sesuai dengan ketentuan etika acara virtual mengenai apa?', 'Menyalakan video wajah dan disiplin menggunakan mikrofon', 'Login lebih awal untuk verifikasi host', 'Mencantumkan nama asli dan unit kerja', 'Menggunakan virtual background sesuai ketentuan', null, 'A', 'Panduan etika acara virtual mewajibkan peserta menyalakan video wajah dan disiplin menggunakan mikrofon; mematikan kamera terus-menerus dan tidak merespons melanggar ketentuan tersebut.', 'medium'),
('b0000000-0000-4000-8000-011000000000', 'Menurut Bab Penutup, etika, kode etik, dan kode perilaku merupakan landasan apa bagi PNS sebagai abdi negara dan pelayan masyarakat?', 'Landasan finansial dan investasi', 'Landasan moral dan profesional', 'Landasan teknis dan administratif semata', 'Landasan hukum pidana khusus', null, 'B', 'Bab Penutup menegaskan etika, kode etik, dan kode perilaku sebagai landasan moral dan profesional yang harus dipegang teguh PNS.', 'easy'),
('b0000000-0000-4000-8000-011000000000', 'Menurut Bab Penutup, kode etik dan kode perilaku bukan sekadar aturan formal, melainkan cerminan dari apa?', 'Kebiasaan lama yang tidak relevan', 'Keputusan pribadi pimpinan semata', 'Nilai dasar ASN dan budaya organisasi', 'Standar internasional yang dipaksakan', null, 'C', 'Kode etik dan kode perilaku mencerminkan nilai dasar ASN dan budaya organisasi, bukan sekadar aturan formal administratif.', 'medium'),
('b0000000-0000-4000-8000-011000000000', 'Kepatuhan terhadap etika, menurut simpulan modul, menjadi ukuran dari apa bagi seorang pegawai?', 'Tingkat pendidikan formal semata', 'Jumlah tunjangan kinerja yang diterima', 'Lama masa kerja seseorang', 'Kematangan pribadi dan profesionalisme', null, 'D', 'Modul menutup dengan menegaskan bahwa kepatuhan terhadap etika menjadi ukuran kematangan pribadi dan profesionalisme pegawai.', 'medium'),
('b0000000-0000-4000-8000-011000000000', 'Cakupan pembahasan modul secara keseluruhan, sebagaimana dirangkum pada Bab Penutup, meliputi prinsip moral, pengertian etika, penerapan kode etik dan kode perilaku, termasuk konteks apa?', 'Sistem kerja fleksibel', 'Pengadaan barang dan jasa pemerintah', 'Sistem informasi manajemen kepegawaian', 'Kebijakan fiskal dan moneter negara', null, 'A', 'Bab Penutup merangkum bahwa modul menguraikan prinsip moral, pengertian etika, penerapan kode etik/perilaku, termasuk konteks sistem kerja fleksibel (SKF).', 'medium'),
('b0000000-0000-4000-8000-011000000000', 'Menurut Bab Penutup, setiap pegawai Kementerian Keuangan bertanggung jawab menjaga nama baik institusi dan kepercayaan masyarakat melalui apa?', 'Pencapaian target penerimaan negara semata', 'Perilaku etis di setiap kondisi kerja', 'Kepatuhan pada jam kerja formal saja', 'Partisipasi dalam kegiatan seremonial', null, 'B', 'Modul menutup dengan pesan bahwa setiap pegawai Kemenkeu bertanggung jawab menjaga nama baik institusi dan kepercayaan masyarakat melalui perilaku etis di setiap kondisi kerja, baik fisik maupun digital.', 'easy')
